mapper.update:
update lkt_bbs_forum

    set like_num = like_num + #{num}


    set collect_num = collect_num + #{num}


    set follow_num = follow_num + #{num}


    set post_num = post_num + #{num}


    where user_id = #{user_id}


    and id = #{id}

mapper.select:
SELECT f.id, f.name, f.user_id, f.description, f.refuse_text, f.status, DATE_FORMAT( f.create_time, '%Y-%m-%d %H:%i:%s' ) AS create_time, f.post_num, u.user_name, u.mobile, f.like_num, f.post_num, f.collect_num FROM lkt_bbs_forum f LEFT JOIN lkt_user u ON f.user_id = u.user_id
order by f.create_time desc
limit #{page},#{pageSize}
